<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $REPO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/engineering/engineering-backend-architect.md</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
